export function sanitizeInput(input: string): string {
  const entityMap: Record<string, string> = {
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#039;'
  };
  return input.replace(/[<>"']/g, (char) => entityMap[char]);
}

